{"path": "semantic_memory.py", "content": """"
Semantic Memory Layer — auto-extract facts & recall via RAG.

Wires RAG (TF-IDF cosine) as long-term semantic memory:
- Extract key facts from conversation → index to RAG
- On each turn, semantic search relevant memories → inject to context
- user-profile.md stays as curated core; RAG handles expanded recall
"""
import os
import re
import time
import json

MEMORY_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), "memory")
SEMANTIC_MEM_PATH = os.path.join(MEMORY_DIR, "semantic-memory.json")
os.makedirs(MEMORY_DIR, exist_ok=True)

# Fact extraction prompt keywords — triggers for "memorable" statements
_FACT_TRIGGERS = [
    "aku ", "saya ", "gue ", "kita ", "nama saya", "namaku", "namague",
    "aku suka", "aku butuh", "aku kerja", "aku pakai", "aku pakai",
    "projectku", "project saya", "preferensi", "favorit", "selalu",
    "jangan", "ingat", "tolong ingat", "catat", "simpan",
    "aku bekerja", "aku develop", "aku build", "stack saya", "tech stack",
    "deploy", "production", "server saya", "domain", "deadline",
]

# Patterns to skip (not memory-worthy)
_SKIP_PATTERNS = [
    re.compile(r"^(oke|iya|ya|nah|hmm|gpp|sip|mantap|keren|bagus)\b", re.I),
    re.compile(r"^\s*\[.+\]", re.I),  # system tags
    re.compile(r"^(terima kasih|makasih|thank)", re.I),
    re.compile(r"^/\w", re.I),  # commands
]


def _load_json():
    if not os.path.exists(SEMANTIC_MEM_PATH):
        return {"facts": [], "last_extract": 0, "last_recall": 0}
    try:
        with open(SEMANTIC_MEM_PATH, "r") as f:
            return json.load(f)
    except Exception:
        return {"facts": [], "last_extract": 0, "last_recall": 0}


def _save_json(data):
    try:
        with open(SEMANTIC_MEM_PATH, "w") as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
    except Exception as e:
        print(f"⚠️ semantic_memory save failed: {e}")


def extract_facts(user_input, assistant_response=""):
    """Extract memory-worthy facts from a conversation turn.

    Returns list of extracted facts (strings). Also indexes them to RAG.
    """
    facts = []

    # Check user input for memorable statements
    for line in user_input.split("\n"):
        line = line.strip()
        if not line or len(line) < 8 or len(line) > 500:
            continue
        # Skip noise
        if any(p.search(line) for p in _SKIP_PATTERNS):
            continue
        # Check triggers
        if any(trig in line.lower() for trig in _FACT_TRIGGERS):
            facts.append(f"[USER] {line}")

    # Check assistant response for decisions/solutions worth remembering
    for line in assistant_response.split("\n"):
        line = line.strip()
        if not line or len(line) < 15:
            continue
        # Remember decisions and solutions
        if any(kw in line.lower() for kw in ["solusi", "fix", "gunakan", "pilih", "install", "deploy", "migrate", "create"]):
            if len(line) < 300:
                facts.append(f"[DECISION] {line}")

    if not facts:
        return []

    # Dedup against existing
    data = _load_json()
    existing = set(f["text"] for f in data["facts"])
    new_facts = [f for f in facts if f not in existing]

    if not new_facts:
        return []

    # Store to JSON
    for f in new_facts:
        data["facts"].append({"text": f, "ts": time.time()})
    data["last_extract"] = time.time()

    # Cap at 500 facts (FIFO)
    if len(data["facts"]) > 500:
        data["facts"] = data["facts"][-500:]

    _save_json(data)

    # Index to RAG for semantic recall
    try:
        import rag_core
        db = rag_core.get_db()
        if db:
            combined = "\n".join(new_facts)
            db.index_text("memory:semantic", combined)
    except Exception:
        pass  # RAG optional, JSON is fallback

    return new_facts


def recall(query, top_n=5):
    """Semantic recall: search RAG for memories relevant to query.

    Returns formatted string for system prompt injection, or None.
    """
    # Method 1: RAG semantic search
    results = []
    try:
        import rag_core
        db = rag_core.get_db()
        if db:
            raw = db.search(query, top_n=top_n)
            # Filter to only memory chunks
            results = [r for r in raw if r.get("file", "").startswith("memory:")
                       or r.get("file", "").startswith("tool:")]
    except Exception:
        pass

    # Method 2: Keyword fallback from JSON
    if not results:
        data = _load_json()
        query_lower = query.lower()
        scored = []
        for fact in data["facts"]:
            text = fact["text"].lower()
            score = sum(1 for word in query_lower.split() if word in text and len(word) > 3)
            if score > 0:
                scored.append((score, fact["text"]))
        scored.sort(key=lambda x: x[0], reverse=True)
        if scored:
            results = [{"content": t, "score": s} for s, t in scored[:top_n]]

    if not results:
        return None

    # Format
    lines = []
    seen = set()
    for r in results:
        content = r.get("content", "").strip()[:200]
        if content and content not in seen:
            seen.add(content)
            lines.append(f"  • {content}")

    if not lines:
        return None

    return "SEMANTIC MEMORY (relevan):\n" + "\n".join(lines)


def get_stats():
    """Return memory stats."""
    data = _load_json()
    return {
        "facts": len(data["facts"]),
        "last_extract": data.get("last_extract", 0),
        "last_recall": data.get("last_recall", 0),
    }
"}

