        m = re.search(r'```(?:json)?\s*(\{.*?\})\s*```', raw, re.DOTALL)
        if m:
            try:
                data = json.loads(m.group(1))
            except Exception:
                pass

    if data and "verdict" in data:
        verdict = data["verdict"].upper()
        if "REFINE" in verdict:
            improved = data.get("improved", "").strip()
            if improved:
                return {
                    "verdict": "REFINE",
                    "issues": data.get("issues", []),
                    "final_text": improved
                }
        return {"verdict": "APPROVED", "issues": data.get("issues", []), "final_text": original_text}

    # Fallback: keyword detection
    low = raw.lower()
    if "refine" in low and "improved" in low:
        # Try to extract improved text
        m = re.search(r'"improved"\s*:\s*"(.+?)"', raw, re.DOTALL)
        if m:
            return {"verdict": "REFINE", "issues": [], "final_text": m.group(1)}
    if "approved" in low:
        return {"verdict": "APPROVED", "issues": [], "final_text": original_text}

    # Default: approve
    return {"verdict": "APPROVED", "issues": [], "final_text": original_text}


