{"content": """"
MCP Client — Model Context Protocol support.

Connects to MCP servers via stdio JSON-RPC 2.0.
Auto-discovers tools, wraps them as agent tools.

Config: mcp_servers.json di project root:
[
  {"name": "filesystem", "command": "npx", "args": ["-y", "@modelcontextprotocol/server-filesystem", "/data/data/com.termux/files/home"]},
  {"name": "sqlite", "command": "python3", "args": ["-m", "mcp_server_sqlite", "--db-path", "memory/semantic-memory.db"]}
]

Flow:
  1. load_config() → baca mcp_servers.json
  2. connect() → spawn each server, initialize handshake
  3. list_tools() → discover tools dari semua server
  4. call_tool(server, tool_name, args) → JSON-RPC call, return result
  5. get_tool_schemas() → wrap MCP tools jadi OpenAI function schema
  6. register_to_agent() → inject ke tools.DISPATCH + TOOLS_SCHEMA

Lifecycle: servers persistent, killed on disconnect/shutdown.
"""
import os
import json
import subprocess
import time
import threading

MCP_CONFIG_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "mcp_servers.json")

# MCP Protocol version
PROTOCOL_VERSION = "2024-11-05"

# JSON-RPC request ID counter
_next_id = 1

# Active server connections: {server_name: {"proc": Popen, "tools": [...]}}
_servers = {}

# Lock for thread-safe stdio communication
_io_lock = threading.Lock()


def _next_request_id():
    global _next_id
    rid = _next_id
    _next_id += 1
    return rid


def load_config():
    """Load MCP server config from JSON file. Returns list of server configs."""
    if not os.path.exists(MCP_CONFIG_PATH):
        return []
    try:
        with open(MCP_CONFIG_PATH, "r") as f:
            return json.load(f)
    except Exception as e:
        print(f"⚠️ MCP config load failed: {e}")
        return []


def _send_request(proc, method, params=None):
    """Send JSON-RPC request to server, read response. Returns result or None."""
    req = {
        "jsonrpc": "2.0",
        "id": _next_request_id(),
        "method": method,
    }
    if params:
        req["params"] = params

    data = json.dumps(req) + "\n"
    try:
        proc.stdin.write(data)
        proc.stdin.flush()
    except (BrokenPipeError, OSError):
        return None

    # Read response line (skip notifications which have no "id")
    deadline = time.time() + 30  # 30s timeout
    while time.time() < deadline:
        line = proc.stdout.readline()
        if not line:
            return None
        line = line.strip()
        if not line:
            continue
        try:
            msg = json.loads(line)
        except json.JSONDecodeError:
            continue
        # Match by id
        if msg.get("id") == req["id"]:
            if "error" in msg:
                err = msg["error"]
                return {"error": err.get("message", str(err))}
            return msg.get("result")
        # Skip notifications (no id) or other responses
    return None


def connect_server(name, command, args=None, env=None):
    """Spawn MCP server process and initialize handshake.

    Returns True on success, False on failure.
    """
    args = args or []
    try:
        full_env = os.environ.copy()
        if env:
            full_env.update(env)

        proc = subprocess.Popen(
            [command] + args,
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env=full_env,
            text=True,
            bufsize=1,  # line-buffered
        )
    except FileNotFoundError:
        print(f"⚠️ MCP server '{name}': command not found: {command}")
        return False
    except Exception as e:
        print(f"⚠️ MCP server '{name}': spawn failed: {e}")
        return False

    # Initialize handshake
    result = _send_request(proc, "initialize", {
        "protocolVersion": PROTOCOL_VERSION,
        "capabilities": {},
        "clientInfo": {
            "name": "sovereign-agent",
            "version": "2.5",
        }
    })

    if result is None:
        print(f"⚠️ MCP server '{name}': initialize timeout/no response")
        proc.kill()
        return False

    if isinstance(result, dict) and "error" in result:
        print(f"⚠️ MCP server '{name}': initialize error: {result['error']}")
        proc.kill()
        return False

    # Send initialized notification
    notif = {"jsonrpc": "2.0", "method": "notifications/initialized"}
    try:
        proc.stdin.write(json.dumps(notif) + "\n")
        proc.stdin.flush()
    except Exception:
        pass

    # Discover tools
    tools_result = _send_request(proc, "tools/list", {})
    tools = []
    if tools_result and isinstance(tools_result, dict):
        tools = tools_result.get("tools", [])

    _servers[name] = {"proc": proc, "tools": tools}
    print(f"✅ MCP server '{name}': connected, {len(tools)} tools discovered")
    return True


def connect_all():
    """Connect to all configured MCP servers. Returns count of successful connections."""
    configs = load_config()
    if not configs:
        return 0

    count = 0
    for cfg in configs:
        name = cfg.get("name", "")
        if not name or name in _servers:
            continue
        command = cfg.get("command", "")
        if not command:
            continue
        if connect_server(name, command, cfg.get("args"), cfg.get("env")):
            count += 1
    return count


def call_tool(server_name, tool_name, arguments):
    """Call a tool on an MCP server.

    Returns string result (for agent tool dispatch compatibility).
    """
    server = _servers.get(server_name)
    if not server:
        return f"[error] MCP server '{server_name}' not connected"

    proc = server["proc"]
    if proc.poll() is not None:
        return f"[error] MCP server '{server_name}' process exited"

    with _io_lock:
        result = _send_request(proc, "tools/call", {
            "name": tool_name,
            "arguments": arguments or {},
        })

    if result is None:
        return f"[error] MCP tool '{tool_name}' timeout"

    if isinstance(result, dict) and "error" in result:
        return f"[error] MCP: {result['error']}"

    # MCP result format: {content: [{type: "text", text: "..."}, ...], isError: bool}
    if isinstance(result, dict):
        if result.get("isError"):
            texts = [c.get("text", "") for c in result.get("content", []) if c.get("type") == "text"]
            return f"[error] {' '.join(texts)}"
        texts = [c.get("text", "") for c in result.get("content", []) if c.get("type") == "text"]
        return "\n".join(texts) if texts else str(result)

    return str(result)


def get_tool_schemas():
    """Get all MCP tools as OpenAI function schemas.

    Tool names are prefixed: "mcp_{server}_{tool}" to avoid collisions.
    Returns (schemas, dispatch_map) where dispatch_map maps tool_name → (server, tool_name).
    """
    schemas = []
    dispatch_map = {}

    for server_name, server in _servers.items():
        for tool in server["tools"]:
            orig_name = tool.get("name", "")
            if not orig_name:
                continue
            prefixed = f"mcp_{server_name}_{orig_name}"
            dispatch_map[prefixed] = (server_name, orig_name)

            # Convert MCP tool schema to OpenAI function schema
            input_schema = tool.get("inputSchema", {"type": "object", "properties": {}})
            schemas.append({
                "type": "function",
                "function": {
                    "name": prefixed,
                    "description": f"[MCP:{server_name}] {tool.get('description', orig_name)}",
                    "parameters": input_schema,
                }
            })

    return schemas, dispatch_map


def get_dispatch_map():
    """Return {prefixed_name: (server_name, orig_tool_name)} for all MCP tools."""
    _, dispatch_map = get_tool_schemas()
    return dispatch_map


def disconnect_all():
    """Kill all MCP server processes."""
    for name, server in _servers.items():
        try:
            server["proc"].kill()
            server["proc"].wait(timeout=5)
        except Exception:
            pass
    _servers.clear()


def get_status():
    """Return status of all MCP connections."""
    status = {}
    for name, server in _servers.items():
        proc = server["proc"]
        status[name] = {
            "alive": proc.poll() is None,
            "tools": len(server["tools"]),
            "tool_names": [t.get("name", "") for t in server["tools"]],
        }
    return status


# ── Agent Integration ─────────────────────────────────

def register_to_tools(tools_module):
    """Dynamically register MCP tools into tools.py DISPATCH + TOOLS_SCHEMA.

    Call this after connect_all() to make MCP tools available to agent.
    """
    schemas, dispatch_map = get_tool_schemas()
    if not schemas:
        return 0

    count = 0
    for prefixed_name, (server_name, orig_name) in dispatch_map.items():
        # Create closure capturing server_name and orig_name
        def make_fn(srv, tool):
            def _dispatch(args):
                return call_tool(srv, tool, args)
            return _dispatch

        tools_module.DISPATCH[prefixed_name] = make_fn(server_name, orig_name)
        count += 1

    # Add schemas to TOOLS_SCHEMA
    for schema in schemas:
        # Avoid duplicates
        name = schema["function"]["name"]
        if not any(s["function"]["name"] == name for s in tools_module.TOOLS_SCHEMA):
            tools_module.TOOLS_SCHEMA.append(schema)

    return count


# ── Self-test ─────────────────────────────────────────

if __name__ == "__main__":
    print("MCP Client self-test")
    print(f"  Protocol version: {PROTOCOL_VERSION}")
    print(f"  Config path: {MCP_CONFIG_PATH}")

    configs = load_config()
    print(f"  Configured servers: {len(configs)}")
    for c in configs:
        print(f"    - {c.get('name')}: {c.get('command')} {' '.join(c.get('args', []))}")

    # Test request ID generation
    assert _next_request_id() == 1
    assert _next_request_id() == 2
    print("  Request ID generator: ✓")

    # Test schema generation (no servers connected)
    schemas, dmap = get_tool_schemas()
    assert schemas == [] and dmap == {}
    print("  Empty schema generation: ✓")

    # Test status
    assert get_status() == {}
    print("  Empty status: ✓")

    print("\nAll tests passed ✓")
    print("\nTo use MCP: create mcp_servers.json, then call connect_all() + register_to_tools(tools)")
