def _dispatch_pipeline(args):
    """Orchestrate multi-agent pipeline: semua jalan paralel → auto-gabung via reporter.

    Contoh: pipeline({
        "agents": [
            {"type": "market_analysis", "params": {"instrument": "XAUUSD", "timeframe": "1D"}},
            {"type": "market_analysis", "params": {"instrument": "EURUSD", "timeframe": "1D"}},
            {"type": "market_analysis", "params": {"instrument": "GBPUSD", "timeframe": "1D"}},
        ],
        "report_title": "Forex Market Analysis",
        "report_format": "trading",
    })
    → 3 market_analysis jalan paralel → hasil digabung reporter → 1 report final
    """
    import concurrent.futures

    agents_config = args.get("agents", [])
    report_title = args.get("report_title", "Pipeline Report")
    report_format = args.get("report_format", "standard")

    # Validate agent types first
    valid_types = {"market_analysis", "risk_analysis", "research"}
    for i, cfg in enumerate(agents_config):
        atype = cfg.get("type", "")
        if atype == "spawn_agents":
            return "[error] tidak boleh nest spawn_agents di dalam pipeline"
        if atype not in valid_types:
            return f"[error] agent {i+1}: type '{atype}' tidak valid. Pilihan: {', '.join(sorted(valid_types))}"

    if len(agents_config) < 2:
        return "[error] butuh minimal 2 agents untuk pipeline"
    if len(agents_config) > 6:
        return "[error] maksimal 6 agents per pipeline"

    results = [None] * len(agents_config)

    def _run_agent(idx_config):
        idx, config = idx_config
        atype = config["type"]
        params = config.get("params", {})

        try:
            dispatch_fn = DISPATCH.get(atype)
            if not dispatch_fn:
                return idx, f"[error] unknown agent type: {atype}"
            result = dispatch_fn(params)
            return idx, result
        except Exception as e:
            return idx, f"[error] agent {idx+1} ({atype}): {e}"

    # Phase 1: Run all agents in parallel
    with concurrent.futures.ThreadPoolExecutor(max_workers=min(4, len(agents_config))) as ex:
        futures = {ex.submit(_run_agent, (i, cfg)): i for i, cfg in enumerate(agents_config)}
        for future in concurrent.futures.as_completed(futures):
            idx, result = future.result()
            results[idx] = result

    # Phase 2: Compile all results
    compiled_data = []
    for i, (cfg, r) in enumerate(zip(agents_config, results)):
        if r is None:
            r = "(no result)"
        atype = cfg["type"]
        label = {
            "market_analysis": f"Market Analysis: {cfg.get('params', {}).get('instrument', '?')}",
            "risk_analysis": f"Risk Assessment: {cfg.get('params', {}).get('instrument', '?')}",
            "research": f"Research: {cfg.get('params', {}).get('query', '?')[:60]}",
        }.get(atype, f"Agent {i+1}: {atype}")
        compiled_data.append(f"### {label}\n{r}")

    raw_data = "\n\n".join(compiled_data)

